'use client';

import { Button } from '@/components/ui/button';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { supabase } from '@/lib/supabaseClient';
import { AlertCircle, Eye, EyeOff, Lock, Mail } from 'lucide-react';
import Image from 'next/image';
import Link from 'next/link';
import { useRouter } from 'next/navigation';
import { useEffect, useMemo, useState } from 'react';

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export default function LoginPage() {
  const router = useRouter();

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isLoggingIn, setIsLoggingIn] = useState(false);
  const [emailTouched, setEmailTouched] = useState(false);
  const [passwordTouched, setPasswordTouched] = useState(false);

  // Redirect already-logged-in users
  useEffect(() => {
    if (typeof window === 'undefined') return;
    if (localStorage.getItem('student')) {
      router.replace('/student');
    } else if (localStorage.getItem('teacher')) {
      router.replace('/teacher');
    } else if (localStorage.getItem('admin')) {
      router.replace('/admin');
    } else if (localStorage.getItem('parent')) {
      router.replace('/parent-dashboard');
    }
  }, [router]);

  const emailError = useMemo(() => {
    if (!email) return 'Email is required.';
    return EMAIL_REGEX.test(email.trim())
      ? null
      : 'Enter a valid email address.';
  }, [email]);

  const passwordError = useMemo(() => {
    if (!password) return 'Password is required.';
    return password.length >= 6
      ? null
      : 'Password must be at least 6 characters.';
  }, [password]);

  const loginDisabled =
    isLoggingIn || !email || !password || Boolean(emailError || passwordError);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setEmailTouched(true);
    setPasswordTouched(true);

    if (emailError || passwordError) {
      setError('Please fix the highlighted fields.');
      return;
    }

    setIsLoggingIn(true);
    setError(null);

    try {
      const trimmedEmail = email.trim().toLowerCase();

      // Detect role from email
      const detectRes = await fetch('/api/auth/detect-role', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email: trimmedEmail }),
      });
      const { role } = await detectRes.json();

      if (!role) {
        setError('No account found with this email address.');
        return;
      }

      if (role === 'student') {
        const res = await fetch('/api/student/login', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ email: trimmedEmail, password }),
        });
        const data = await res.json();
        if (!res.ok || !data.success) {
          setError(data.error || 'Invalid email or password.');
          return;
        }
        localStorage.setItem('student', JSON.stringify(data.student));
        router.push(data.firstLogin ? '/student?firstLogin=true' : '/student');
      } else if (role === 'teacher') {
        const res = await fetch('/api/teacher/login', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ email: trimmedEmail, password }),
        });
        const data = await res.json();
        if (!res.ok || !data.success) {
          setError(data.error || 'Invalid email or password.');
          return;
        }
        localStorage.setItem('teacher', JSON.stringify(data.teacher));
        router.push('/teacher');
      } else if (role === 'parent' || role === 'admin') {
        const { data: authData, error: authError } =
          await supabase.auth.signInWithPassword({
            email: trimmedEmail,
            password,
          });

        if (authError || !authData.user) {
          setError(authError?.message || 'Invalid email or password.');
          return;
        }

        const { data: userProfile, error: profileError } = await supabase
          .from('users')
          .select('*')
          .ilike('email', trimmedEmail)
          .eq('role', role)
          .single();

        if (profileError || !userProfile) {
          await supabase.auth.signOut();
          setError('Account not found. Please contact support.');
          return;
        }

        if (role === 'admin') {
          localStorage.setItem('admin', JSON.stringify(userProfile));
          router.push('/admin');
        } else {
          localStorage.setItem('parent', JSON.stringify(userProfile));

          const { data: relationships } = await supabase
            .from('user_relationships')
            .select(
              'related_user_id, users!user_relationships_related_user_id_fkey(*)'
            )
            .eq('user_id', userProfile.id)
            .eq('users.role', 'student');

          if (relationships) {
            const children = relationships
              .map((rel: any) => rel.users)
              .filter(Boolean);
            localStorage.setItem('parentChildren', JSON.stringify(children));
          }

          router.push('/parent-dashboard');
        }
      } else {
        setError('Unknown account type. Please contact support.');
      }
    } catch (err: any) {
      console.error('Login error:', err);
      const msg = err?.message || String(err) || '';
      if (
        msg.toLowerCase().includes('network') ||
        msg.includes('Failed to fetch')
      ) {
        setError('Network error. Please check your connection and try again.');
      } else {
        setError(msg || 'An unexpected error occurred. Please try again.');
      }
    } finally {
      setIsLoggingIn(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-amber-50 to-orange-50 flex items-center justify-center px-4 py-8">
      {isLoggingIn && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-8 flex flex-col items-center">
            <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-red-800 mb-4" />
            <p className="text-gray-700 font-medium">Logging in...</p>
            <p className="text-gray-500 text-sm mt-2">Please wait</p>
          </div>
        </div>
      )}

      <Card className="w-full max-w-md border-gray-200 shadow-lg">
        <CardHeader className="text-center pb-2">
          <div className="flex justify-center mb-4">
            <Image
              src="/logo.png"
              alt="Sto Niño de Praga Academy Logo"
              width={80}
              height={80}
              className="rounded-full"
            />
          </div>
          <CardTitle className="text-2xl font-bold text-red-800">
            Sign In
          </CardTitle>
          <CardDescription>Sto Niño de Praga Academy</CardDescription>
        </CardHeader>

        <CardContent>
          <form onSubmit={handleLogin} className="space-y-4" noValidate>
            <div className="space-y-2">
              <Label htmlFor="login-email" className="text-gray-800">
                <Mail className="w-4 h-4 inline mr-2" />
                Email
              </Label>
              <Input
                id="login-email"
                type="email"
                placeholder="Enter your email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                onBlur={() => setEmailTouched(true)}
                aria-invalid={emailTouched && Boolean(emailError)}
                aria-describedby="login-email-error"
                autoComplete="email"
                required
                disabled={isLoggingIn}
                className="border-gray-200"
              />
              {emailTouched && emailError && (
                <p id="login-email-error" className="text-sm text-red-600">
                  {emailError}
                </p>
              )}
            </div>

            <div className="space-y-2">
              <Label htmlFor="login-password" className="text-gray-800">
                <Lock className="w-4 h-4 inline mr-2" />
                Password
              </Label>
              <div className="relative">
                <Input
                  id="login-password"
                  type={showPassword ? 'text' : 'password'}
                  placeholder="Enter your password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  onBlur={() => setPasswordTouched(true)}
                  aria-invalid={passwordTouched && Boolean(passwordError)}
                  aria-describedby="login-password-error"
                  autoComplete="current-password"
                  required
                  disabled={isLoggingIn}
                  className="border-gray-200 pr-10"
                />
                <button
                  type="button"
                  onClick={() => setShowPassword((prev) => !prev)}
                  className="absolute inset-y-0 right-3 flex items-center text-gray-500 hover:text-gray-800 focus:outline-none"
                  aria-label={showPassword ? 'Hide password' : 'Show password'}
                >
                  {showPassword ? (
                    <EyeOff className="w-4 h-4" />
                  ) : (
                    <Eye className="w-4 h-4" />
                  )}
                </button>
              </div>
              {passwordTouched && passwordError && (
                <p id="login-password-error" className="text-sm text-red-600">
                  {passwordError}
                </p>
              )}
            </div>

            {error && (
              <div
                className="flex items-start space-x-2 text-red-700 text-sm bg-red-50 p-3 rounded"
                role="alert"
              >
                <AlertCircle className="w-4 h-4 mt-0.5 flex-shrink-0" />
                <p aria-live="assertive">{error}</p>
              </div>
            )}

            <Button
              type="submit"
              disabled={loginDisabled}
              className="w-full bg-red-800 hover:bg-red-700 disabled:opacity-60"
            >
              {isLoggingIn ? 'Logging in...' : 'Login'}
            </Button>

            <div className="text-center pt-2">
              <Link
                href="/"
                className="text-sm text-gray-500 hover:text-red-700 transition-colors"
              >
                ← Back to Home
              </Link>
            </div>
          </form>
        </CardContent>
      </Card>
    </div>
  );
}
